using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product {i}",
                Price = 10m * i,
                Quantity = i
            })
            .ToList();

    #region CreateOrder - Success cases

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateItems();

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithNonEmptyId()
    {
        // Arrange
        var items = CreateItems();

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 25.50m, Quantity = 3 }
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalAcrossAllItems()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 10m, Quantity = 2 },  // 20
            new() { ProductName = "B", Price = 5m, Quantity = 4 },   // 20
            new() { ProductName = "C", Price = 100m, Quantity = 1 }, // 100
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(140m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var items = CreateItems();
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsGreaterThan(before.AddSeconds(-1), order.CreatedAt);
        Assert.IsLessThan(after.AddSeconds(1), order.CreatedAt);
    }

    [TestMethod]
    public void CreateOrder_StoresItemsOnOrder()
    {
        // Arrange
        var items = CreateItems(3);

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.HasCount(3, order.Items);
    }

    #endregion

    #region CreateOrder - Validation / Exceptions

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems();

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var emptyItems = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", emptyItems));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var created = _service.CreateOrder("cust-1", CreateItems());

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistingId_ReturnsNull()
    {
        // Act
        var result = _service.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        // Act
        var orders = _service.GetOrdersByCustomer("no-orders-customer");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        _service.CreateOrder("cust-A", CreateItems());
        _service.CreateOrder("cust-A", CreateItems(2));
        _service.CreateOrder("cust-B", CreateItems());

        // Act
        var orders = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomersOrders()
    {
        // Arrange
        _service.CreateOrder("cust-A", CreateItems());
        _service.CreateOrder("cust-B", CreateItems());

        // Act
        var orders = _service.GetOrdersByCustomer("cust-A");

        // Assert
        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual("cust-A", single.CustomerId);
    }

    #endregion
}

